import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import './App.css';
import Header from './components/Header';
import RunningStrip from './components/RunningStrip';
import AdGrid from './components/AdGrid';
import Footer from './components/Footer';
import Success from './components/Success';
import Purchase from './components/Purchase';
import Checkout from './components/Checkout';
import BusinessDetails from './components/BusinessDetails';

function App() {
  return (
    <Router>
      <div className="App">
        <Header />
        <RunningStrip />
        
        <Routes>
          {/* Home route - Page 1 */}
          <Route path="/" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Direct Advertising Platform 🚀</h1>
                <h5>🔻 Learn more about ClickaLinks in our footer information menu 🔻</h5>
              </div>
              <AdGrid pageNumber={1} />
            </div>
          } />
          
          {/* Page 2 */}
          <Route path="/page2" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 2 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={2} />
            </div>
          } />
          
          {/* Page 3 */}
          <Route path="/page3" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 3 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={3} />
            </div>
          } />
          
          {/* Page 4 */}
          <Route path="/page4" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 4 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={4} />
            </div>
          } />
          
          {/* Page 5 */}
          <Route path="/page5" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 5 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={5} />
            </div>
          } />
          
          {/* Page 6 */}
          <Route path="/page6" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 6 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={6} />
            </div>
          } />
          
          {/* Page 7 */}
          <Route path="/page7" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 7 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={7} />
            </div>
          } />
          
          {/* Page 8 */}
          <Route path="/page8" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 8 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={8} />
            </div>
          } />
          
          {/* Page 9 */}
          <Route path="/page9" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 9 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={9} />
            </div>
          } />
          
          {/* Page 10 */}
          <Route path="/page10" element={
            <div className="container">
              <div className="hero">
                <h1>🚀 Advertising Page 10 🚀</h1>
                <h5>🔻 200 premium advertising squares available 🔻</h5>
              </div>
              <AdGrid pageNumber={10} />
            </div>
          } />
          
          {/* Purchase Flow Routes */}
          <Route path="/purchase" element={<Purchase />} />
          <Route path="/business-details" element={<BusinessDetails />} />
          <Route path="/checkout" element={<Checkout />} />
          <Route path="/success" element={<Success />} />
        </Routes>
        
        <Footer />
      </div>
    </Router>
  );
}

export default App;
